"use client"

import { useEffect, useMemo, useRef, useState } from "react"
import { Clipboard, Check } from "lucide-react"

import FileIcon from "./FileIcon"
import CodePath from "./CodePath"
import { CodeBlockFrame } from "./CodeBlockFrame"
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip"

interface WalkthroughStep {
  title: string
  body: string
  lines: string
}

interface CodeWalkthroughClientProps {
  language?: string
  filename?: string
  filepath: string
  code: string
  title?: string
  htmlByStep: string[]
  steps: WalkthroughStep[]
}

function formatLanguage(language?: string): string {
  if (!language) return "TEXT"
  return language.toUpperCase()
}

function parseRange(range: string): { start?: number; end?: number } {
  const match = range.trim().match(/^(\d+)\s*-\s*(\d+)$/)
  if (!match) return {}
  return {
    start: Number(match[1]),
    end: Number(match[2]),
  }
}

export function CodeWalkthroughClient({
  language = "ts",
  filename,
  filepath,
  code,
  title = "Code walkthrough",
  htmlByStep,
  steps,
}: CodeWalkthroughClientProps) {
  const [activeIndex, setActiveIndex] = useState(0)
  const [copied, setCopied] = useState(false)
  const codeScrollRef = useRef<HTMLDivElement>(null)

  const activeStep = steps[activeIndex]

  useEffect(() => {
    const el = codeScrollRef.current?.querySelector(".highlight-line")
    if (el) {
      el.scrollIntoView({
        block: "center",
        behavior: "smooth",
      })
    }
  }, [activeIndex])

  async function handleCopy() {
    await navigator.clipboard.writeText(code)
    setCopied(true)
    window.setTimeout(() => setCopied(false), 1500)
  }

  const focusLabel = useMemo(() => {
    if (!activeStep) return null
    const { start, end } = parseRange(activeStep.lines)
    if (!start || !end) return null
    return start === end ? `focus line ${start}` : `focus lines ${start}-${end}`
  }, [activeStep])

  return (
    <TooltipProvider delayDuration={200}>
      <section className="my-8 space-y-4">
        <div className="space-y-1">
          <h3 className="text-base font-semibold text-foreground">{title}</h3>
          <p className="text-sm text-muted-foreground">
            Clique une étape pour mettre en évidence la zone correspondante dans le code.
          </p>
        </div>

        <div className="grid gap-4 lg:grid-cols-[320px_minmax(0,1fr)]">
          {/* Colonne explications */}
          <aside className="rounded-xl border bg-card">
            <div className="max-h-[70vh] overflow-auto p-3">
              <div className="space-y-2">
                {steps.map((step, index) => (
                  <button
                    key={`${step.title}-${index}`}
                    type="button"
                    onClick={() => setActiveIndex(index)}
                    className={`w-full rounded-lg border p-3 text-left transition ${
                      index === activeIndex
                        ? "border-primary/30 bg-primary/10"
                        : "border-border bg-background hover:bg-muted/40"
                    }`}
                  >
                    <div className="text-sm font-medium text-foreground">
                      {index + 1}. {step.title}
                    </div>
                    <div className="mt-1 text-sm leading-6 text-muted-foreground">
                      {step.body}
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </aside>

          {/* Vrai bloc code indépendant */}
          <div className="overflow-hidden rounded-xl border border-white/10 bg-[#12141a] shadow-sm">
            <div className="sticky top-0 z-20 border-b border-white/10 bg-[#12141a]/95 px-4 py-3 backdrop-blur supports-[backdrop-filter]:bg-[#12141a]/80">
              <div className="flex items-start justify-between gap-4">
                <div className="min-w-0">
                  <div className="truncate text-sm font-medium text-white">
                    {activeStep?.title ?? title}
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  <span className="rounded-md border border-white/10 bg-white/[0.04] px-2 py-1 text-[11px] font-medium tracking-wide text-white/70">
                    {formatLanguage(language)}
                  </span>

                  <Tooltip>
                    <TooltipTrigger asChild>
                      <button
                        type="button"
                        onClick={handleCopy}
                        className="flex h-7 w-7 items-center justify-center rounded-md border border-white/10 bg-white/[0.04] text-white/70 transition hover:bg-white/[0.07] hover:text-white"
                      >
                        {copied ? (
                          <Check size={14} className="text-green-400" />
                        ) : (
                          <Clipboard size={14} />
                        )}
                      </button>
                    </TooltipTrigger>

                    <TooltipContent side="bottom">
                      {copied ? "Copied!" : "Copy"}
                    </TooltipContent>
                  </Tooltip>
                </div>
              </div>

              <div className="mt-2 flex items-center justify-between gap-4">
                <div className="flex min-w-0 items-center gap-2 overflow-hidden">
                  <FileIcon language={language} filepath={filepath} />
                  <CodePath filepath={filepath} />
                </div>

                {focusLabel ? (
                  <div className="shrink-0 text-xs text-white/45">{focusLabel}</div>
                ) : null}
              </div>
            </div>

            <div
              ref={codeScrollRef}
              className="max-h-[70vh] overflow-auto bg-[#12141a]"
            >
              <CodeBlockFrame html={htmlByStep[activeIndex] ?? ""} />
            </div>
          </div>
        </div>
      </section>
    </TooltipProvider>
  )
}

export default CodeWalkthroughClient